	<div class="add-update-preview">
		<el-form
			class="add-update-form"
			ref="ruleForm"
			:model="ruleForm"
			:rules="rules"
			label-width="200px"
			>
			<el-form-item class="add-item" label="博主" prop="screenname">
				<el-input v-model="ruleForm.screenname" 
					placeholder="博主" clearable :readonly="ro.screenname"></el-input>
			</el-form-item>
			<el-form-item class="add-item" label="评论数" prop="commentscount">
				<el-input v-model.number="ruleForm.commentscount" 
					placeholder="评论数" clearable :readonly="ro.commentscount"></el-input>
			</el-form-item>
			<el-form-item class="add-item" label="转发数" prop="repostscount">
				<el-input v-model.number="ruleForm.repostscount" 
					placeholder="转发数" clearable :readonly="ro.repostscount"></el-input>
			</el-form-item>
			<el-form-item class="add-item" label="点赞数" prop="attitudescount">
				<el-input v-model.number="ruleForm.attitudescount" 
					placeholder="点赞数" clearable :readonly="ro.attitudescount"></el-input>
			</el-form-item>
			<el-form-item class="add-item" label="发布时间" prop="fbtime">
				<el-input v-model="ruleForm.fbtime" 
					placeholder="发布时间" clearable :readonly="ro.fbtime"></el-input>
			</el-form-item>
			<el-form-item class="add-item" label="媒体" prop="medias">
				<el-input v-model="ruleForm.medias" 
					placeholder="媒体" clearable :readonly="ro.medias"></el-input>
			</el-form-item>
			<el-form-item class="add-item" label="博文" prop="mblogtext">
				<el-input
					type="textarea"
					:rows="8"
					:disabled="ro.mblogtext"
					placeholder="博文"
					v-model="ruleForm.mblogtext">
					</el-input>
			</el-form-item>
			<el-form-item class="add-item" label="主页地址" prop="userurl">
				<el-input
					type="textarea"
					:rows="8"
					:disabled="ro.userurl"
					placeholder="主页地址"
					v-model="ruleForm.userurl">
					</el-input>
			</el-form-item>

			<el-form-item class="add-btn-item">
				<el-button class="submitBtn"  type="primary" @click="onSubmit(null)">
					<span class="icon iconfont icon-xiugai17"></span>
					<span class="text">提交信息</span>
				</el-button>
				<el-button class="closeBtn" @click="back()">
					<span class="icon iconfont icon-shanchu8"></span>
					<span class="text">取消</span>
				</el-button>
			</el-form-item>
		</el-form>
	</div>
</template>

<script>
	export default {
		data() {
			return {
				id: '',
				baseUrl: '',
				ro:{
					screenname : false,
					mblogtext : false,
					commentscount : false,
					repostscount : false,
					attitudescount : false,
					fbtime : false,
					medias : false,
					userurl : false,
					thumbsupnum : false,
					crazilynum : false,
					clicktime : false,
					clicknum : false,
					discussnum : false,
					storeupnum : false,
				},
				type: '',
				userTableName: localStorage.getItem('UserTableName'),
				ruleForm: {
					screenname: '',
					mblogtext: '',
					commentscount: '',
					repostscount: '',
					attitudescount: '',
					fbtime: '',
					medias: '',
					userurl: '',
					thumbsupnum: '',
					crazilynum: '',
					clicktime: '',
					clicknum: '',
					discussnum: '',
					storeupnum: '',
				},

				rules: {
					screenname: [
					],
					mblogtext: [
					],
					commentscount: [
						{ validator: this.$validate.isIntNumer, trigger: 'blur' },
					],
					repostscount: [
						{ validator: this.$validate.isIntNumer, trigger: 'blur' },
					],
					attitudescount: [
						{ validator: this.$validate.isIntNumer, trigger: 'blur' },
					],
					fbtime: [
					],
					medias: [
					],
					userurl: [
						{ validator: this.$validate.isURL, trigger: 'blur' },
					],
					thumbsupnum: [
						{ validator: this.$validate.isIntNumer, trigger: 'blur' },
					],
					crazilynum: [
						{ validator: this.$validate.isIntNumer, trigger: 'blur' },
					],
					clicktime: [
					],
					clicknum: [
						{ validator: this.$validate.isIntNumer, trigger: 'blur' },
					],
					discussnum: [
						{ validator: this.$validate.isIntNumer, trigger: 'blur' },
					],
					storeupnum: [
						{ validator: this.$validate.isIntNumer, trigger: 'blur' },
					],
				},
				centerType: false,
			};
		},
		computed: {
			sessionForm() {
				return JSON.parse(localStorage.getItem('sessionForm'))
			},



		},
		components: {
		},
		created() {
			if(this.$route.query.centerType){
				this.centerType = true
			}
			//this.bg();
			let type = this.$route.query.type ? this.$route.query.type : '';
			this.init(type);
			this.baseUrl = this.$config.baseUrl;
		},
		methods: {
			getMakeZero(s) {
				return s < 10 ? '0' + s : s;
			},
			// 下载
			download(file ){
				window.open(`${file}`)
			},
			// 初始化
			init(type) {
				this.type = type;
				if(type=='cross'){
					var obj = JSON.parse(localStorage.getItem('crossObj'));
					for (var o in obj){
						if(o=='screenname'){
							this.ruleForm.screenname = obj[o];
							this.ro.screenname = true;
							continue;
						}
						if(o=='mblogtext'){
							this.ruleForm.mblogtext = obj[o];
							this.ro.mblogtext = true;
							continue;
						}
						if(o=='commentscount'){
							this.ruleForm.commentscount = obj[o];
							this.ro.commentscount = true;
							continue;
						}
						if(o=='repostscount'){
							this.ruleForm.repostscount = obj[o];
							this.ro.repostscount = true;
							continue;
						}
						if(o=='attitudescount'){
							this.ruleForm.attitudescount = obj[o];
							this.ro.attitudescount = true;
							continue;
						}
						if(o=='fbtime'){
							this.ruleForm.fbtime = obj[o];
							this.ro.fbtime = true;
							continue;
						}
						if(o=='medias'){
							this.ruleForm.medias = obj[o];
							this.ro.medias = true;
							continue;
						}
						if(o=='userurl'){
							this.ruleForm.userurl = obj[o];
							this.ro.userurl = true;
							continue;
						}
						if(o=='thumbsupnum'){
							this.ruleForm.thumbsupnum = obj[o];
							this.ro.thumbsupnum = true;
							continue;
						}
						if(o=='crazilynum'){
							this.ruleForm.crazilynum = obj[o];
							this.ro.crazilynum = true;
							continue;
						}
						if(o=='clicktime'){
							this.ruleForm.clicktime = obj[o];
							this.ro.clicktime = true;
							continue;
						}
						if(o=='clicknum'){
							this.ruleForm.clicknum = obj[o];
							this.ro.clicknum = true;
							continue;
						}
						if(o=='discussnum'){
							this.ruleForm.discussnum = obj[o];
							this.ro.discussnum = true;
							continue;
						}
						if(o=='storeupnum'){
							this.ruleForm.storeupnum = obj[o];
							this.ro.storeupnum = true;
							continue;
						}
					}
				}else if(type=='edit'){
					this.info()
				}

				if (localStorage.getItem('raffleType') && localStorage.getItem('raffleType') != null) {
					localStorage.removeItem('raffleType')
					setTimeout(() => {
						this.onSubmit(null)
					}, 300)
				}
			},

			// 多级联动参数
			// 多级联动参数
			async info() {
				await this.$http.get(`bloginfo/detail/${this.$route.query.id}`, {emulateJSON: true}).then(res => {
					if (res.data.code == 0) {
						this.ruleForm = res.data.data;
					}
				});
			},
			// 提交
			async onSubmit(subMitType=null) {
				if(!this.ruleForm.id) {
					delete this.ruleForm.userid
				}
				await this.$refs["ruleForm"].validate(async valid => {
					if(valid) {
						if(this.type=='cross'){
							var statusColumnName = localStorage.getItem('statusColumnName');
							var statusColumnValue = localStorage.getItem('statusColumnValue');
							if(statusColumnName && statusColumnName!='') {
								var obj = JSON.parse(localStorage.getItem('crossObj'));
								if(!statusColumnName.startsWith("[")) {
									for (var o in obj){
										if(o==statusColumnName){
											obj[o] = statusColumnValue;
										}
									}
									var table = localStorage.getItem('crossTable');
									await this.$http.post(table+'/update', obj).then(res => {});
								}
							}
						}

						await this.$http.post(`bloginfo/${this.ruleForm.id?'update':this.centerType?'save':'add'}`, this.ruleForm).then(async res => {
							if (res.data.code == 0) {
								await this.$message({
									message: '操作成功',
									type: 'success',
									duration: 1500,
									onClose: () => {
										this.$router.go(-1);
										
									}
								});
							} else {
								this.$message({
									message: res.data.msg,
									type: 'error',
									duration: 1500
								});
							}
						});
					}
				});
			},
			// 获取uuid
			getUUID () {
				return new Date().getTime();
			},
			// 返回
			back() {
				this.$router.go(-1);
			},
		}
	};
</script>

