						label="评论内容">
						<template slot-scope="scope">
							{{scope.row.plcontent}}
						</template>
					</el-table-column>
					<el-table-column :resizable='true' :sortable='false'
						prop="likecount"
						label="支持数">
						<template slot-scope="scope">
							{{scope.row.likecount}}
						</template>
					</el-table-column>
					<el-table-column :resizable='true' :sortable='false'
						prop="fbplace"
						label="发布地">
						<template slot-scope="scope">
							{{scope.row.fbplace}}
						</template>
					</el-table-column>
					<el-table-column :resizable='true' :sortable='false'
						prop="pltime"
						label="评论时间">
						<template slot-scope="scope">
							{{scope.row.pltime}}
						</template>
					</el-table-column>
					<el-table-column :resizable='true' :sortable='false'
						prop="clicknum"
						label="点击次数">
						<template slot-scope="scope">
							{{scope.row.clicknum}}
						</template>
					</el-table-column>
					<el-table-column :resizable='true' :sortable='false'
						prop="discussnum"
						label="评论数">
						<template slot-scope="scope">
