						</template>
					</el-table-column>
					<el-table-column :resizable='true' :sortable='false'
						prop="storeupnum"
						label="收藏数">
						<template slot-scope="scope">
							{{scope.row.storeupnum}}
						</template>
					</el-table-column>
					<el-table-column width="300" label="操作">
						<template slot-scope="scope">
							<el-button class="table-view" type="success" @click.native="toDetail(scope.row)">
								<span class="icon iconfont icon-fangdajing02"></span>
								查看
							</el-button>
							<el-button class="table-btn1" type="success" @click.native="discussClick(scope.row)" v-if="btnAuth('blogcomment','查看评论')">
								<span class="icon iconfont icon-xiaoxi-zhihui"></span>
								查看评论
							</el-button>
							<el-button class="table-btn5" type="success" @click.native="chapterClick(scope.row)" v-if="btnAuth('blogcomment','章节管理')">
								<span class="icon iconfont icon-zhangjie7"></span>
								章节管理
							</el-button>
						</template>
					</el-table-column>
				</el-table>
			</div>

	
